import{_ as n,m as o,k as r,ah as t,q as e}from"./chunks/framework.BgQAHmMj.js";const a="/docs/images/core-concepts/section-page-relation-fr-light.svg",c="/docs/images/core-concepts/section-page-relation-fr-dark.svg",i="/docs/images/core-concepts/singleton-vs-collection-fr-light.svg",l="/docs/images/core-concepts/singleton-vs-collection-fr-dark.svg",C=JSON.parse('{"title":"Concepts de base","description":"","frontmatter":{"layout":"doc"},"headers":[],"relativePath":"fr/developers/getting-started/core-concepts.md","filePath":"src/fr/developers/getting-started/core-concepts.md"}'),d={name:"fr/developers/getting-started/core-concepts.md"},p=a+"#light-only",u=c+"#dark-only",m=i+"#light-only",g=l+"#dark-only";function _(h,s,f,q,b,v){return r(),o("div",null,[...s[0]||(s[0]=[t('<h1 id="concepts-de-base" tabindex="-1">Concepts de base <a class="header-anchor" href="#concepts-de-base" aria-label="Permalink to &quot;Concepts de base&quot;">​</a></h1><h2 id="les-sections" tabindex="-1">Les sections <a class="header-anchor" href="#les-sections" aria-label="Permalink to &quot;Les sections&quot;">​</a></h2><p>L&#39;élément de base de Creopse est la section, elle peut être définie comme un bloc de contenu contextualisé et localisé. Toute section possède une structure de données permettant d&#39;organiser son contenu et des paramètres permettant d&#39;adapter son rendu.</p><h2 id="les-pages" tabindex="-1">Les pages <a class="header-anchor" href="#les-pages" aria-label="Permalink to &quot;Les pages&quot;">​</a></h2><p>Les pages dans Creopse sont des empilements de sections dont on peut modifier la position et le contenu. Chaque page peut comporter autant de sections que nécessaire, et le contenu de chacune est lié à la page sur laquelle elle se trouve. Une même section peut ainsi être utilisée sur plusieurs pages avec des contenus différents, ou apparaître plusieurs fois sur une même page. Il est également possible de lier le contenu d&#39;une section à son contenu sur une autre page.</p>',5),e("p",null,[e("img",{src:p,alt:"Section / Page relationship"}),e("img",{src:u,alt:"Section / Page relationship"})],-1),t('<h2 id="les-modeles-de-contenu" tabindex="-1">Les modèles de contenu <a class="header-anchor" href="#les-modeles-de-contenu" aria-label="Permalink to &quot;Les modèles de contenu&quot;">​</a></h2><p>Les modèles de contenu sont des modèles de données qui permettent de récupérer du contenu lié au contexte métier de la plateforme et qui peut être utilisé un peu partout, par exemple des services, des articles, des produits, etc. Ils sont accessibles depuis n&#39;importe quelle section de n&#39;importe quelle page.</p><h2 id="les-structures-de-donnees" tabindex="-1">Les structures de données <a class="header-anchor" href="#les-structures-de-donnees" aria-label="Permalink to &quot;Les structures de données&quot;">​</a></h2><p>Les structures de données sont des descriptions de la forme des données qui constituent le contenu de divers éléments comme les sections et les modèles de contenu. Elles permettent à Creopse de générer les champs nécessaires pour récupérer les données constituant le contenu dans l&#39;interface d&#39;administration.</p><p>On distingue deux types de composantes dans les structures de données :</p><ul><li><strong>Les singletons</strong> :</li></ul><p>Ce sont des composantes qui permettent de récupérer des données de contenus simples, par exemple un titre, une image, un texte, etc.</p><ul><li><strong>Les collections</strong> :</li></ul><p>Ce sont des composantes qui permettent de récupérer des données de contenus complexes et répétitifs, par exemple une liste de membres d&#39;équipe, une liste de témoignages clients, etc.</p>',9),e("p",null,[e("img",{src:m,alt:"Singleton vs Collection"}),e("img",{src:g,alt:"Singleton vs Collection"})],-1)])])}const L=n(d,[["render",_]]);export{C as __pageData,L as default};
